// UTF-8 sanitizer: replace malformed chars before processing
function sanitizeText(s) {
  if (!s) return s;
  return String(s)
    .replace(/\uFFFD/g, '')   // replacement char
    .replace(/\u0000/g, '')   // null bytes
    .trim();
}

const msg = $input.item.json;

// Parse sender from 'from' field: "Name <email>" or bare "email@domain"
const fromRaw = msg.from || '';
const emailMatch = fromRaw.match(/<([^>]+)>/) || fromRaw.match(/([^\s]+@[^\s]+)/);
const senderEmail = emailMatch ? emailMatch[1].toLowerCase().trim() : null;
const senderDomain = senderEmail ? senderEmail.split('@')[1] : null;

// Prefer plain text; fall back to stripping HTML
let rawText = msg.text || '';
if (!rawText && msg.html) {
  rawText = msg.html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
}
rawText = rawText.substring(0, 10000);

// COST SAVER: skip empty/near-empty mails — previously "" was sent to the LLM with the full 10KB system prompt
if (rawText.trim().length < 10) return [];

// Build thread key from In-Reply-To or References header if available
const messageId = msg.messageId || msg.headers?.['message-id'] || null;

return [{
  json: {
    normalized_input: {
      input_source: 'email',
      source_detail: 'email',
      email_account_id: 'mailde_main',
      email_address: $env.MAILDE_ADDRESS || null,
      email_provider: 'imap',
      subject: msg.subject || null,
      date: msg.date || new Date().toISOString(),
      raw_text: rawText,
      raw_meta: {
        message_id: messageId,
        sender: fromRaw,
        sender_email: senderEmail,
        sender_domain: senderDomain
      }
    }
  }
}];

// ============================================================
// Sender Risk Check - shared across all email flows
// ============================================================

const ni = $input.item.json.normalized_input;
const senderEmail  = (ni.raw_meta && ni.raw_meta.sender_email)  || null;
const senderDomain = (ni.raw_meta && ni.raw_meta.sender_domain) ||
                     (senderEmail ? senderEmail.split('@')[1] : null);
const subject      = (ni.subject || '').toLowerCase();
const rawText      = (ni.raw_text || '').toLowerCase();

const LEGIT_DOMAINS = new Set([
